"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["737"],{8103(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/stratum-core/docs/intro","label":"Introduction to Stratum","docId":"intro","unlisted":false},{"type":"link","href":"/stratum-core/docs/architecture","label":"Architecture Overview","docId":"architecture","unlisted":false},{"type":"link","href":"/stratum-core/docs/database-schema","label":"Database Schema Reference","docId":"database-schema","unlisted":false},{"type":"link","href":"/stratum-core/docs/api-reference","label":"API Reference","docId":"api-reference","unlisted":false},{"type":"link","href":"/stratum-core/docs/mcp-server","label":"Model Context Protocol (MCP)","docId":"mcp-server","unlisted":false}]},"docs":{"api-reference":{"id":"api-reference","title":"API Reference","description":"The Stratum backend exposes a REST HTTP API for managing projects, configuring data sources, executing database queries, and checking pipeline runs. All endpoints are prefixed with /api/.","sidebar":"tutorialSidebar"},"architecture":{"id":"architecture","title":"Architecture Overview","description":"Stratum consists of an integrated analytical database, an ingestion and enrichment pipeline, a REST API server, and a React frontend. This guide details how these components interact.","sidebar":"tutorialSidebar"},"database-schema":{"id":"database-schema","title":"Database Schema Reference","description":"Stratum utilizes DuckDB for storing and analyzing bibliographic datasets. The schema consists of five main tables representing papers, authors, institutions, countries, and author contributions.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction to Stratum","description":"Stratum is a high-performance bibliographic metadata retrieval, storage, and enrichment platform. It helps researchers, data scientists, and AI agents fetch academic paper metadata from APIs like OpenAlex and Crossref, store them in a fast local analytical database (DuckDB), and enrich/impute missing metadata such as institutional affiliations and countries.","sidebar":"tutorialSidebar"},"mcp-server":{"id":"mcp-server","title":"Model Context Protocol (MCP)","description":"Stratum implements the Model Context Protocol (MCP) to allow AI assistants (such as Claude Desktop or Gemini) to run database queries, manage configuration, download records, and trigger imputation pipelines directly on your local system.","sidebar":"tutorialSidebar"}}}}')}}]);